sp_widget.client_script:
function($scope, $location) {
    var c = this;

    c.navigateTo = function(path) {
        $location.path(path);
    };

    c.viewIncident = function(incidentId) {
        $location.path('/incident').search({sys_id: incidentId});
    };
}

sp_widget.css:
.sre-dashboard {
    padding: var(--carbon-spacing-05);
}

.dashboard-header {
    margin-bottom: var(--carbon-spacing-06);
}

.dashboard-header h1 {
    color: var(--carbon-text-01);
    font-size: 2rem;
    margin-bottom: var(--carbon-spacing-03);
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-03);
}

.dashboard-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
    gap: var(--carbon-spacing-05);
    margin-bottom: var(--carbon-spacing-06);
}

.dashboard-card {
    background: var(--carbon-ui-01);
    border: 1px solid var(--carbon-ui-03);
    border-radius: 4px;
    padding: var(--carbon-spacing-05);
}

.dashboard-card h2 {
    color: var(--carbon-text-01);
    font-size: 1.25rem;
    margin-bottom: var(--carbon-spacing-04);
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-03);
}

.quick-links {
    display: flex;
    flex-direction: column;
    gap: var(--carbon-spacing-03);
}

.quick-link {
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-03);
    padding: var(--carbon-spacing-03);
    background: var(--carbon-ui-background);
    border: 1px solid var(--carbon-ui-03);
    border-radius: 4px;
    cursor: pointer;
    transition: all 0.2s ease;
    text-decoration: none;
    color: var(--carbon-text-01);
}

.quick-link:hover {
    border-color: var(--carbon-interactive-01);
    background: var(--carbon-hover-ui);
}

.metric-card {
    background: var(--carbon-ui-background);
    border: 1px solid var(--carbon-ui-03);
    border-radius: 4px;
    padding: var(--carbon-spacing-04);
    text-align: center;
}

.metric-value {
    font-size: 2rem;
    font-weight: 600;
    color: var(--carbon-text-01);
}

.metric-value.critical {
    color: #da1e28;
}

.metric-value.warning {
    color: #f1c21b;
}

.metric-value.good {
    color: #24a148;
}

.metric-label {
    font-size: 0.875rem;
    color: var(--carbon-text-02);
    margin-top: var(--carbon-spacing-02);
}

.incident-item {
    padding: var(--carbon-spacing-03);
    background: var(--carbon-ui-background);
    border: 1px solid var(--carbon-ui-03);
    border-radius: 4px;
    cursor: pointer;
    margin-bottom: var(--carbon-spacing-03);
}

.incident-item:hover {
    border-color: var(--carbon-interactive-01);
}

.incident-priority {
    display: inline-block;
    padding: 2px 8px;
    border-radius: 2px;
    font-size: 0.75rem;
    font-weight: 600;
}

.incident-priority.p1 {
    background: #da1e28;
    color: white;
}

.incident-priority.p2 {
    background: #f1c21b;
    color: black;
}

